def findTargetSumWays(nums, target):
    def helper(idx, curr_sum, prev_sign):
        if idx == len(nums):
            return 1 if curr_sum == target else 0
        total = 0
        if idx == 0:
            # First number: both + and - allowed
            total += helper(idx+1, curr_sum + nums[idx], 1)
            total += helper(idx+1, curr_sum - nums[idx], -1)
        else:
            # Must use different sign than previous
            if prev_sign == 1:
                total += helper(idx+1, curr_sum - nums[idx], -1)
            else:
                total += helper(idx+1, curr_sum + nums[idx], 1)
        return total
    if not nums:
        return 1 if target == 0 else 0
    return helper(0, 0, 0)

