def find_most_common_note(compositions):
    period_notes = {}
    for period, composition in compositions:
        if period not in period_notes:
            period_notes[period] = {}
        for note, count in composition.items():
            if note not in period_notes[period]:
                period_notes[period][note] = 0
            period_notes[period][note] += count
