def fibonacci(n, memoize=False):
    if n < 0:
        return -1
    if memoize:
        if n == 0:
            return 0
        elif n == 1:
            return 1
        fibs = [0] * (n + 1)
        fibs[0] = 0
        fibs[1] = 1
        for i in range(2, n + 1):
            fibs[i] = fibs[i-1] + fibs[i-2]
        return fibs[n]
    else:
        if n == 0:
            return 0
        elif n == 1:
            return 1
        else:
            return fibonacci(n-1, False) + fibonacci(n-2, False)

