from typing import List, Tuple, Optional

def stack_tops(m: int, ops: List[Tuple[int, int, Optional[int]]]) -> List[int]:
    # Store the original operation list in order of their indices (1-based to 0-based)
    original_ops = [None]*m
    for i in range(m):
        p, t, x = ops[i]
        if t == 1:
            original_ops[p-1] = (1, x)
        else:
            original_ops[p-1] = (0, None)

    enabled = [False]*m
    result = []
    # We keep an in-order list of current-enabled operations (as indices) to simulate the remembered history
    remembered_indices = set()
    applied_indices = []
    for i in range(m):
        p, t, x = ops[i]
        idx = p-1
        enabled[idx] = True
        # Find all operations that have been enabled, by index order
        stack = []
        for j in range(m):
            if enabled[j]:
                op_type, val = original_ops[j]
                if op_type == 1:
                    stack.append(val)
                else:
                    if stack:
                        stack.pop()
        top = stack[-1] if stack else -1
        result.append(top)
    return result

