        twos = candies.count(2)
        total = ones + 2 * twos
        if total % 2 != 0:
            result.append("NO")
        else:
            target = total // 2
            # To reach 'target', we use as many 2's as possible without exceeding target
            max_twos_used = min(twos, target // 2)
            rem = target - 2 * max_twos_used
            # rem is to be filled with 1's
